15	// runScriptFn executes a directive file against opts.WorkDir using real filesystem
16	// and git operations. The directive file path is taken from opts.Model (if it is
17	// a readable file) or from opts.PromptFile as a fallback.
18	func runScriptFn(r *Runner, opts RunOptions) (*Result, error) {
19		start := time.Now()
20	
21		// Resolve directive file: opts.Model first, then opts.PromptFile.
22		directivePath := opts.Model
23		if directivePath == "" || !isReadableFile(directivePath) {
24			if opts.PromptFile != "" {
25				directivePath = opts.PromptFile
26			}
27		}
28		if directivePath == "" {
29			return nil, fmt.Errorf("script harness: no directive file (set --model or --prompt-file)")
30		}
31	
32		data, err := os.ReadFile(directivePath)
33		if err != nil {
34			return nil, fmt.Errorf("script harness: read directive file %s: %w", directivePath, err)
35		}
36	
37		workDir := opts.WorkDir
38		if workDir == "" {
39			workDir = "."
40		}
41	
42		var outputLines []string
43		exitCode := 0
44		var execErr error
45	
46		directives := parseDirectives(string(data))
47	
48		// Build env interpolation map from Correlation.
49		envMap := map[string]string{
50			"DDX_BEAD_ID":         "",
51			"DDX_ATTEMPT_ID":      "",
52			"DDX_WORKER_ID":       "",
53			"DDX_SESSION_LOG_DIR": opts.SessionLogDir,
54		}
55		if opts.Correlation != nil {
56			if v, ok := opts.Correlation["bead_id"]; ok {
57				envMap["DDX_BEAD_ID"] = v
58			}
59			if v, ok := opts.Correlation["attempt_id"]; ok {
60				envMap["DDX_ATTEMPT_ID"] = v
61			}
62			if v, ok := opts.Correlation["worker_id"]; ok {
63				envMap["DDX_WORKER_ID"] = v
64			}
65		}
66		expand := func(s string) string {
67			return os.Expand(s, func(key string) string {
68				return envMap[key]
69			})
70		}
71	
72		for i, d := range directives {
73			verb := d[0]
74			args := d[1:]
75	
76			switch verb {
77			case "no-op":
78				outputLines = append(outputLines, "no-op")
79	
80			case "set-exit":
81				if len(args) < 1 {
82					execErr = fmt.Errorf("script harness: set-exit requires an argument")
83					goto done
84				}
85				n, err := strconv.Atoi(args[0])
86				if err != nil {
87					execErr = fmt.Errorf("script harness: set-exit: invalid code %q", args[0])
88					goto done
89				}
90				exitCode = n
91	
92			case "sleep-ms":
93				if len(args) < 1 {
94					execErr = fmt.Errorf("script harness: sleep-ms requires an argument")
95					goto done
96				}
97				n, err := strconv.Atoi(args[0])
98				if err != nil {
99					execErr = fmt.Errorf("script harness: sleep-ms: invalid duration %q", args[0])
100					goto done
101				}
102				time.Sleep(time.Duration(n) * time.Millisecond)
103	
104			case "fail-during":
105				if len(args) < 1 {
106					execErr = fmt.Errorf("script harness: fail-during requires an argument")
107					goto done
108				}
109				n, err := strconv.Atoi(args[0])
110				if err != nil {
111					execErr = fmt.Errorf("script harness: fail-during: invalid index %q", args[0])
112					goto done
113				}
114				if i == n {
115					execErr = fmt.Errorf("script harness: synthetic failure at directive %d", i)
116					goto done
117				}
118	
119			case "append-line":
120				if len(args) < 2 {
121					execErr = fmt.Errorf("script harness: append-line requires path and text")
122					goto done
123				}
124				path, err := resolvePath(workDir, expand(args[0]))
125				if err != nil {
126					execErr = err
127					goto done
128				}
129				text := expand(strings.Join(args[1:], " "))
130				if err := os.MkdirAll(filepath.Dir(path), 0755); err != nil {
131					execErr = fmt.Errorf("script harness: append-line mkdir: %w", err)
132					goto done
133				}
134				f, err := os.OpenFile(path, os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0644)
135				if err != nil {
136					execErr = fmt.Errorf("script harness: append-line open: %w", err)
137					goto done
138				}
139				_, werr := fmt.Fprintln(f, text)
140				f.Close()
141				if werr != nil {
142					execErr = fmt.Errorf("script harness: append-line write: %w", werr)
143					goto done
144				}
145				outputLines = append(outputLines, fmt.Sprintf("append-line %s", args[0]))
146	
147			case "create-file":
148				if len(args) < 2 {
149					execErr = fmt.Errorf("script harness: create-file requires path and content")
150					goto done
151				}
152				path, err := resolvePath(workDir, expand(args[0]))
153				if err != nil {
154					execErr = err
155					goto done
156				}
157				content := expand(strings.Join(args[1:], " "))
158				if err := os.MkdirAll(filepath.Dir(path), 0755); err != nil {
159					execErr = fmt.Errorf("script harness: create-file mkdir: %w", err)
160					goto done
161				}
162				if err := os.WriteFile(path, []byte(content), 0644); err != nil {
163					execErr = fmt.Errorf("script harness: create-file write: %w", err)
164					goto done
165				}
166				outputLines = append(outputLines, fmt.Sprintf("create-file %s", args[0]))
167	
168			case "delete-file":
169				if len(args) < 1 {
170					execErr = fmt.Errorf("script harness: delete-file requires a path")
171					goto done
172				}
173				path, err := resolvePath(workDir, expand(args[0]))
174				if err != nil {
175					execErr = err
176					goto done
177				}
178				if err := os.Remove(path); err != nil && !os.IsNotExist(err) {
179					execErr = fmt.Errorf("script harness: delete-file: %w", err)
180					goto done
181				}
182				outputLines = append(outputLines, fmt.Sprintf("delete-file %s", args[0]))
183	
184			case "modify-line":
185				if len(args) < 3 {
186					execErr = fmt.Errorf("script harness: modify-line requires path, regex, and replacement")
187					goto done
188				}
189				path, err := resolvePath(workDir, expand(args[0]))
190				if err != nil {
191					execErr = err
192					goto done
193				}
194				pattern := expand(args[1])
195				repl := expand(strings.Join(args[2:], " "))
196				re, err := regexp.Compile(pattern)
197				if err != nil {
198					execErr = fmt.Errorf("script harness: modify-line: bad regex %q: %w", pattern, err)
199					goto done
200				}
201				raw, err := os.ReadFile(path)
202				if err != nil {
203					execErr = fmt.Errorf("script harness: modify-line read: %w", err)
204					goto done
205				}
206				lines := strings.Split(string(raw), "\n")
207				for li, line := range lines {
208					if re.MatchString(line) {
209						lines[li] = re.ReplaceAllString(line, repl)
210						break
211					}
212				}
213				if err := os.WriteFile(path, []byte(strings.Join(lines, "\n")), 0644); err != nil {
214					execErr = fmt.Errorf("script harness: modify-line write: %w", err)
215					goto done
216				}
217				outputLines = append(outputLines, fmt.Sprintf("modify-line %s", args[0]))
218	
219			case "run":
220				if len(args) < 1 {
221					execErr = fmt.Errorf("script harness: run requires a shell command")
222					goto done
223				}
224				shell := expand(strings.Join(args, " "))
225				cmd := exec.Command("sh", "-c", shell)
226				cmd.Dir = workDir
227				cmd.Env = scrubbedGitEnvScript()
228				out, err := cmd.CombinedOutput()
229				outputLines = append(outputLines, strings.TrimRight(string(out), "\n"))
230				if err != nil {
231					execErr = fmt.Errorf("script harness: run %q: %w", shell, err)
232					goto done
233				}
234	
235			case "commit":
236				if len(args) < 1 {
237					execErr = fmt.Errorf("script harness: commit requires a message")
238					goto done
239				}
240				msg := expand(strings.Join(args, " "))
241				if err := gitCommitAll(workDir, msg); err != nil {
242					execErr = fmt.Errorf("script harness: commit: %w", err)
243					goto done
244				}
245				outputLines = append(outputLines, fmt.Sprintf("commit %q", msg))
246	
247			default:
248				execErr = fmt.Errorf("script harness: unknown directive %q at index %d", verb, i)
249				goto done
250			}
251		}
252	
253	done:
254		elapsed := time.Since(start)
255		sessionID := fmt.Sprintf("script-%d", start.UnixNano())
256	
257		result := &Result{
258			Harness:        "script",
259			Provider:       "script",
260			RouteReason:    "direct-override",
261			Model:          directivePath,
262			Output:         strings.Join(outputLines, "\n"),
263			ExitCode:       exitCode,
264			DurationMS:     int(elapsed.Milliseconds()),
265			AgentSessionID: sessionID,
266		}
267		if execErr != nil {
268			result.Error = execErr.Error()
269			if result.ExitCode == 0 {
270				result.ExitCode = 1
271			}
272		}
273		return result, execErr
274	}
