276	// parseDirectives parses a directive file into a slice of token slices.
277	// Lines starting with # are comments. Empty lines are skipped.
278	// Tokens are whitespace-separated; a quoted string in position 2+ is kept together.
279	func parseDirectives(content string) [][]string {
280		var out [][]string
281		scanner := bufio.NewScanner(strings.NewReader(content))
282		for scanner.Scan() {
283			line := strings.TrimSpace(scanner.Text())
284			if line == "" || strings.HasPrefix(line, "#") {
285				continue
286			}
287			tokens := splitDirective(line)
288			if len(tokens) == 0 {
289				continue
290			}
291			out = append(out, tokens)
292		}
293		return out
294	}
