296	// splitDirective splits a directive line into tokens.
297	// Returns [verb, arg1, arg2, ...] where the final argument absorbs any
298	// remaining whitespace-separated words as a single string. Surrounding
299	// double-quotes on the final argument are stripped.
300	//
301	// For directives that need 3 distinct args (modify-line: path regex repl)
302	// we return verb + 3 separate fields: parts[0..2], with parts[3:] joined
303	// onto the last field.
304	//
305	// The heuristic: each case in RunScript knows how many discrete args it
306	// needs and accesses them by index; the split just returns all fields, and
307	// the caller joins args[N:] for the "rest" argument.
308	func splitDirective(line string) []string {
309		// We need to preserve the raw fields so callers can pick the right number.
310		// Return all whitespace-split tokens; the final quoted token has quotes stripped.
311		parts := strings.Fields(line)
312		if len(parts) == 0 {
313			return nil
314		}
315		// Strip quotes from the last token if the entire last token is quoted.
316		last := parts[len(parts)-1]
317		if len(last) >= 2 && last[0] == '"' && last[len(last)-1] == '"' {
318			parts[len(parts)-1] = last[1 : len(last)-1]
319		}
320		return parts
321	}
