323	// resolvePath resolves a relative path against workDir and rejects absolute paths.
324	func resolvePath(workDir, path string) (string, error) {
325		if filepath.IsAbs(path) {
326			return "", fmt.Errorf("script harness: absolute path rejected: %s", path)
327		}
328		return filepath.Join(workDir, path), nil
329	}
