331	// gitCommitAll runs git add -A && git commit -m msg in dir with scrubbed GIT_* env.
332	func gitCommitAll(dir, msg string) error {
333		for _, args := range [][]string{
334			{"add", "-A"},
335			{"commit", "-m", msg},
336		} {
337			cmd := exec.Command("git", args...)
338			cmd.Dir = dir
339			cmd.Env = scrubbedGitEnvScript()
340			if out, err := cmd.CombinedOutput(); err != nil {
341				return fmt.Errorf("git %v: %w\n%s", args, err, out)
342			}
343		}
344		return nil
345	}
346	
347	// scrubbedGitEnvScript returns the environment with all GIT_* variables removed.
348	func scrubbedGitEnvScript() []string {
349		parent := os.Environ()
350		env := make([]string, 0, len(parent))
351		for _, kv := range parent {
352			if strings.HasPrefix(kv, "GIT_") {
353				continue
354			}
355			env = append(env, kv)
356		}
357		return env
358	}
